#!/usr/bin/env node
'use strict';
/**
 * Bundle gen-context.js + all src/ modules into a single standalone file.
 * Output: gen-context.standalone.js — copy this one file to any project, no src/ needed.
 *
 * Usage: node scripts/bundle.js
 */

const fs   = require('fs');
const path = require('path');

const ROOT  = path.join(__dirname, '..');
const ENTRY = path.join(ROOT, 'gen-context.js');
const SRC   = path.join(ROOT, 'src');
const OUT   = path.join(ROOT, 'gen-context.standalone.js');

// ── 1. Collect all src modules → canonical key map ──────────────────────────
function collectModules(dir) {
  const results = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) results.push(...collectModules(full));
    else if (entry.name.endsWith('.js')) results.push(full);
  }
  return results;
}

const modFiles = collectModules(SRC);

// Canonical key: './src/config/loader'  (relative to ROOT, always forward slashes)
function canonicalKey(absPath) {
  return './' + path.relative(ROOT, absPath).replace(/\\/g, '/').replace(/\.js$/, '');
}

// Build a map: canonical key -> absolute path
const keyToPath = new Map();
for (const f of modFiles) keyToPath.set(canonicalKey(f), f);

// ── 2. Resolve a require string inside a given src file ──────────────────────
function resolveRequire(requireStr, fromAbsPath) {
  const fromDir = path.dirname(fromAbsPath);
  let abs = path.resolve(fromDir, requireStr);
  // Only intercept if it resolves inside src/
  if (!abs.startsWith(SRC)) return null; // Leave Node built-ins alone

  if (!abs.endsWith('.js')) abs += '.js';
  const key = canonicalKey(abs);
  return keyToPath.has(key) ? key : null;
}

// ── 3. Patch require calls in a source string ────────────────────────────────
function patchRequires(src, fromAbsPath) {
  // Match require('...') and require("...")
  return src.replace(/require\((['"])(\.{1,2}\/[^'"]+)\1\)/g, (match, quote, reqStr) => {
    const canon = resolveRequire(reqStr, fromAbsPath);
    if (!canon) return match; // not an internal module
    return `__require(${quote}${canon}${quote})`;
  });
}

// ── 4. Build inline module registry code ────────────────────────────────────
let registryCode = '';

for (const [key, absPath] of keyToPath) {
  let content = fs.readFileSync(absPath, 'utf8');
  // Strip 'use strict' — outer file already has it
  content = content.replace(/^'use strict';\n?/, '');
  // Patch internal require calls
  content = patchRequires(content, absPath);

  registryCode += `
// ── ${key} ──
__factories[${JSON.stringify(key)}] = function(module, exports) {
${content.split('\n').map(l => '  ' + l).join('\n')}
};
`;
}

// ── 5. Patch the main entry file ─────────────────────────────────────────────
let main = fs.readFileSync(ENTRY, 'utf8');

// Patch top-level require('./src/...')
main = main.replace(/require\((['"])(\.\/src\/[^'"]+)\1\)/g, (match, quote, reqStr) => {
  // Normalise: strip .js suffix if present
  const key = reqStr.replace(/\.js$/, '');
  return `__require(${quote}${key}${quote})`;
});

// Also patch lazy requires inside functions (same pattern, same regex already covers them)

// Remove the entry shebang so the bundled output has only one at the top.
main = main.replace(/^#!.*\n/, '');

// Remove 'use strict' from main — we put it at top of output
main = main.replace(/^'use strict';\n?/, '');

// ── 6. Assemble final output ─────────────────────────────────────────────────
const bootstrap = `#!/usr/bin/env node
'use strict';
// ContextForge — standalone bundle (generated by scripts/bundle.js)
// Copy this single file to any project: node gen-context.js --setup
// No src/ directory required. Node.js 18+ only. Zero npm dependencies.

const __factories = {};
const __cache = {};
function __require(key) {
  if (Object.prototype.hasOwnProperty.call(__cache, key)) {
    return __cache[key].exports;
  }
  if (!Object.prototype.hasOwnProperty.call(__factories, key)) {
    throw new Error('[context-forge] bundled module not found: ' + key);
  }
  const module = { exports: {} };
  __cache[key] = module;
  __factories[key](module, module.exports);
  return module.exports;
}

${registryCode}
`;

const output = bootstrap + main;

fs.writeFileSync(OUT, output, 'utf8');

const kb = Math.round(output.length / 1024);
const lines = output.split('\n').length;
console.log(`[bundle] ✓ wrote ${path.relative(ROOT, OUT)}`);
console.log(`         ${lines} lines, ${kb} KB`);
console.log(`         modules inlined: ${keyToPath.size}`);
